/** Family for a species, or 'Unknown' if not catalogued. */
export function getFamily(botanicalName: string): string {
  return speciesFamily[botanicalName] ?? 'Unknown'
}

/** Genus = first word of the botanical name. */
export function getGenus(botanicalName: string): string {
  return botanicalName.split(' ')[0] || botanicalName
}
